using System.Collections.Concurrent;
using sv_30268be374f949729c188c9096b7cf50.Models;

namespace sv_30268be374f949729c188c9096b7cf50.Services;

/// <summary>
/// Singleton store that holds wizard data keyed by session cookie value.
/// Per-page interactivity destroys the circuit on every navigation, so scoped
/// services cannot carry state across pages. This singleton, combined with a
/// cookie set by middleware, provides per-user persistence.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionKey)
    {
        var state = _states.GetOrAdd(sessionKey, _ => new WizardState());
        state.LastAccessed = DateTime.UtcNow;
        return state;
    }

    public void RemoveExpired(TimeSpan maxAge)
    {
        var cutoff = DateTime.UtcNow - maxAge;
        foreach (var kvp in _states)
        {
            if (kvp.Value.LastAccessed < cutoff)
                _states.TryRemove(kvp.Key, out _);
        }
    }
}

using Microsoft.AspNetCore.Components;
using sv_30268be374f949729c188c9096b7cf50.Models;
using sv_30268be374f949729c188c9096b7cf50.Services;

namespace sv_30268be374f949729c188c9096b7cf50.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Resolves the session key from either
/// HttpContext (prerender) or PersistentComponentState (interactive) and
/// loads the shared WizardState from the singleton store.
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;

    protected WizardState Wizard { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;
    private string _sessionKey = "";

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("WizardSessionKey", out var key))
        {
            // Interactive phase — restored from prerender.
            _sessionKey = key!;
        }
        else
        {
            // Prerender phase — read from HttpContext (set by middleware).
            _sessionKey = HttpContextAccessor.HttpContext?
                .Items["WizardSessionKey"]?.ToString() ?? "";
        }

        if (!string.IsNullOrEmpty(_sessionKey))
        {
            Wizard = Store.GetOrCreate(_sessionKey);
        }
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("WizardSessionKey", _sessionKey);
        return Task.CompletedTask;
    }

    protected void CompleteStepAndNavigate(int stepNumber, string nextPath)
    {
        Wizard.CompletedSteps.Add(stepNumber);
        Navigation.NavigateTo(nextPath);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

