.wizard-container {
    max-width: 800px;
    margin: 0 auto;
}

.wizard-progress {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1.5rem 0;
    gap: 0;
}

.wizard-step {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-decoration: none;
    color: #6c757d;
    gap: 0.4rem;
    min-width: 90px;
}

.wizard-step:hover {
    text-decoration: none;
    color: #495057;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 2px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    background: #fff;
    transition: all 0.2s;
}

.step-label {
    font-size: 0.8rem;
    white-space: nowrap;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    min-width: 30px;
    max-width: 80px;
    margin-bottom: 1.6rem;
    transition: background 0.2s;
}

.step-connector.active {
    background: #0d6efd;
}

/* Current step */
.wizard-step.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.wizard-step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

/* Completed step */
.wizard-step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.wizard-step.completed .step-label {
    color: #198754;
}

.step-indicator {
    text-align: center;
    font-size: 0.9rem;
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.wizard-body {
    padding: 0 1rem 2rem;
}

