@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Personal Information</PageTitle>

<h3>Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Wizard.PersonalInfo.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">
        Next &rarr;
    </button>
</div>

@code {
    private void Next() => CompleteStepAndNavigate(1, "/apply/experience");
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Experience</PageTitle>

<h3>Work Experience</h3>

@if (Wizard.Experience.Jobs.Count == 0)
{
    <p class="text-muted">No job history entries yet. Click "Add Job" to get started.</p>
}

@for (int i = 0; i < Wizard.Experience.Jobs.Count; i++)
{
    var job = Wizard.Experience.Jobs[i];
    var index = i;

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-start mb-2">
                <h6 class="card-subtitle text-muted">Job @(index + 1)</h6>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">
                    Remove
                </button>
            </div>
            <div class="mb-2">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="job.Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="job.Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Duration</label>
                <input class="form-control" @bind="job.Duration" placeholder="e.g. 2 years" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">
    + Add Job
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">
        &larr; Back
    </button>
    <button class="btn btn-primary" @onclick="Next">
        Next &rarr;
    </button>
</div>

@code {
    private void AddJob() => Wizard.Experience.Jobs.Add(new());

    private void RemoveJob(int index) => Wizard.Experience.Jobs.RemoveAt(index);

    private void Back() => Navigation.NavigateTo("/apply/personal-info");

    private void Next() => CompleteStepAndNavigate(2, "/apply/references");
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>References</PageTitle>

<h3>References</h3>

@if (Wizard.References.Contacts.Count == 0)
{
