            </div>
            <div class="mb-2">
                <label class="form-label">Email</label>
                <input class="form-control" type="email" @bind="contact.Email" />
            </div>
            <div class="mb-2">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="contact.Relationship"
