    private void Next() => CompleteStepAndNavigate(3, "/apply/review");
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Review Application</PageTitle>

<h3>Review Your Application</h3>

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <a href="/apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@DisplayOrEmpty(Wizard.PersonalInfo.Name)</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@DisplayOrEmpty(Wizard.PersonalInfo.Email)</dd>
        </dl>
    </div>
</div>

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work Experience</strong>
        <a href="/apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        @if (Wizard.Experience.Jobs.Count == 0)
        {
            <p class="text-muted mb-0">No job history entered.</p>
        }
        else
        {
            @foreach (var job in Wizard.Experience.Jobs)
            {
                <div class="mb-2 @(job != Wizard.Experience.Jobs[^1] ? "pb-2 border-bottom" : "")">
                    <strong>@DisplayOrEmpty(job.Title)</strong>
                    at @DisplayOrEmpty(job.Company)
                    <br />
                    <small class="text-muted">@DisplayOrEmpty(job.Duration)</small>
                </div>
            }
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <a href="/apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        @if (Wizard.References.Contacts.Count == 0)
        {
            <p class="text-muted mb-0">No references entered.</p>
        }
        else
        {
            @foreach (var contact in Wizard.References.Contacts)
            {
                <div class="mb-2 @(contact != Wizard.References.Contacts[^1] ? "pb-2 border-bottom" : "")">
                    <strong>@DisplayOrEmpty(contact.Name)</strong>
                    — @DisplayOrEmpty(contact.Relationship)
                    <br />
                    <small class="text-muted">@DisplayOrEmpty(contact.Email)</small>
                </div>
            }
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">
        &larr; Back
    </button>
    <button class="btn btn-success" @onclick="Submit">
        Submit Application
    </button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3" role="alert">
        Your application has been submitted successfully!
    </div>
}

@code {
    private bool _submitted;

    private static string DisplayOrEmpty(string? value) =>
        string.IsNullOrWhiteSpace(value) ? "—" : value;

    private void Back() => Navigation.NavigateTo("/apply/references");

    private void Submit()
    {
        Wizard.CompletedSteps.Add(4);
        _submitted = true;
    }
}

