using sv_30268be374f949729c188c9096b7cf50.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateStore>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Wizard session middleware — assigns a session cookie and stores the key
// in HttpContext.Items so both the static layout and prerendered interactive
// components can look up wizard state from the singleton store.
app.Use(async (context, next) =>
{
    string sessionKey;
    if (context.Request.Cookies.TryGetValue("WizardSession", out var existing))
    {
        sessionKey = existing;
    }
    else
    {
        sessionKey = Guid.NewGuid().ToString("N");
        context.Response.Cookies.Append("WizardSession", sessionKey, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(24)
        });
    }
    context.Items["WizardSessionKey"] = sessionKey;
    await next();
});

app.UseAntiforgery();

